# 📦 1. Capabilities Test (JS for your IDE Console)

```js
// ========================================================
// BIGDADDYG AGENTIC CAPABILITY TEST SUITE
// ========================================================

(async function runAgenticTest() {
    console.log("=== AGENTIC CAPABILITY TEST STARTED ===");

    const results = {};

    // ----------------------------------------------------
    // 1. Test File Read Access
    // ----------------------------------------------------
    try {
        const r = await fetch("/fs/read?path=index.html").then(r=>r.json());
        results.fileRead = r.success ? "OK" : "FAIL";
    } catch(e) { results.fileRead = "FAIL: " + e.message; }

    // ----------------------------------------------------
    // 2. Test File Write Access
    // ----------------------------------------------------
    try {
        const w = await fetch("/fs/write", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ path: "agentic_test.txt", content: "hi" })
        }).then(r=>r.json());
        results.fileWrite = w.success ? "OK" : "FAIL";
    } catch(e) { results.fileWrite = "FAIL: " + e.message; }

    // ----------------------------------------------------
    // 3. Test Terminal Command Access
    // ----------------------------------------------------
    try {
        const c = await fetch("/terminal/run", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ cmd: "echo agentic_terminal" })
        }).then(r=>r.json());
        results.terminal = c.output.includes("agentic_terminal") ? "OK" : "FAIL";
    } catch(e) { results.terminal = "FAIL: " + e.message; }

    // ----------------------------------------------------
    // 4. Test clang access
    // ----------------------------------------------------
    try {
        const clang = await fetch("/terminal/run", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ cmd: "clang --version" })
        }).then(r=>r.json());
        results.clang = clang.output ? "OK" : "FAIL";
    } catch(e) { results.clang = "FAIL"; }

    // ----------------------------------------------------
    // 5. Test Execute C code
    // ----------------------------------------------------
    try {
        const code = `
        #include <stdio.h>
        int main(){ printf("C_WORKS"); }
        `;
        await fetch("/fs/write", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ path: "test.c", content: code })
        });

        const build = await fetch("/terminal/run", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ cmd: "clang test.c -o test_c" })
        }).then(r=>r.json());

        const exec = await fetch("/terminal/run", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ cmd: "./test_c" })
        }).then(r=>r.json());

        results.clangRun = exec.output.includes("C_WORKS") ? "OK" : "FAIL";
    } catch(e) { results.clangRun = "FAIL"; }

    // ----------------------------------------------------
    // 6. Test Browser Permissions
    // ----------------------------------------------------
    try {
        results.browser = window?.navigator ? "OK" : "FAIL";
    } catch(e) { results.browser = "FAIL"; }

    // ----------------------------------------------------
    // 7. Test Local Models (Ollama)
    // ----------------------------------------------------
    try {
        const o = await fetch("http://localhost:11434/api/tags").then(r=>r.json());
        results.ollama = Array.isArray(o.models) ? "OK" : "FAIL";
    } catch(e) { results.ollama = "FAIL"; }

    // ----------------------------------------------------
    // 8. Test AI Self-Debugging Capture
    // ----------------------------------------------------
    try {
        console.debug("SELF_DEBUG_TEST");
        results.selfDebug = "OK (console.debug intercepted)";
    } catch(e) { results.selfDebug = "FAIL"; }

    console.log("=== AGENTIC TEST RESULTS ===");
    console.table(results);

})();
```

